{"path": "/tmp/sv-beb4f92059a44287b7b468106732ab8c/Components/Pages/Board/Board.razor", "file_text": "@page "/board"
@using sv_beb4f92059a44287b7b468106732ab8c.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (isLoading)
{
    <p class="loading-message">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <p class="error-message">@errorMessage</p>
}
else
{
    <BoardStats Tasks="allTasks" />

    <TaskSearchBar SearchTerm="@searchTerm" SearchTermChanged="HandleSearchChanged" />

    <div class="kanban-board">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="id => MoveTask(id, "In Progress")"
                      OnAddTask="args => AddTask(args, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, "To Do")"
                      OnMoveRight="id => MoveTask(id, "Done")"
                      OnAddTask="args => AddTask(args, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, "In Progress")"
                      OnAddTask="args => AddTask(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks = allTasks.Select(t => t.Id == taskId ? t with { Status = newStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}
"}

